        // ==================== 工具函数 ====================
        
        // 生成ID
        function generateId() {
            return Date.now().toString(36) + Math.random().toString(36).substr(2);
        }
        
        // 格式化时间
        function formatTime(timeString) {
            const date = new Date(timeString);
            
            // 检查时间是否有效
            if (isNaN(date.getTime())) {
                return ''; // 返回空字符串而不是NaN/NaN
            }
            
            const now = new Date();
            
            if (date.toDateString() === now.toDateString()) {
                return `${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
            }
            
            const yesterday = new Date(now);
            yesterday.setDate(yesterday.getDate() - 1);
            if (date.toDateString() === yesterday.toDateString()) {
                return "昨天";
            }
            
            const weekAgo = new Date(now);
            weekAgo.setDate(weekAgo.getDate() - 7);
            if (date > weekAgo) {
                const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
                return days[date.getDay()];
            }
            
            return `${date.getMonth() + 1}/${date.getDate()}`;
        }
        
        // 按日期分组消息
        function groupMessagesByDate(messages) {
            const groups = {};
            
            messages.forEach(message => {
                const date = new Date(message.time).toLocaleDateString('zh-CN');
                if (!groups[date]) {
                    groups[date] = [];
                }
                groups[date].push(message);
            });
            
            return groups;
        }
        
        // 转义HTML
        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }
        
        // 显示通知
        function showNotification(message, type = 'success') {
            const notification = document.getElementById('notification');
            const notificationText = document.getElementById('notificationText');
            
            notificationText.textContent = message;
            notification.className = 'notification';
            
            if (type === 'error') {
                notification.classList.add('error');
                notification.querySelector('i').className = 'fas fa-exclamation-circle';
            } else if (type === 'info') {
                notification.classList.add('info');
                notification.querySelector('i').className = 'fas fa-info-circle';
            } else if (type === 'warning') {
                notification.classList.add('warning');
                notification.querySelector('i').className = 'fas fa-exclamation-triangle';
            } else {
                notification.querySelector('i').className = 'fas fa-check-circle';
            }
            
            notification.classList.add('show');
            
            setTimeout(() => {
                notification.classList.remove('show');
            }, 3000);
        }

        // 显示聊天气泡通知 (改为发送给父窗口显示全局通知)
        function showChatBubble(chat, messageText) {
            // 获取头像信息
            const contact = appData.contacts.find(c => c.id === chat.contactId);
            let avatarData = null;
            let avatarColor = chat.avatarColor;
            let avatarText = chat.avatarText;
            let name = chat.name;

            if (contact) {
                name = contact.name;
                if (contact.hasCustomAvatar) {
                    const avatarKey = `avatar_${contact.id}`;
                    const storedAvatar = localStorage.getItem(avatarKey);
                    if (storedAvatar) {
                         avatarData = storedAvatar;
                         avatarText = ''; // 有自定义头像时不显示默认文字
                     } else {
                         avatarColor = contact.avatarColor;
                         avatarText = contact.avatarText;
                     }
                } else {
                    avatarColor = contact.avatarColor;
                    avatarText = contact.avatarText;
                }
            } else {
                avatarColor = chat.avatarColor;
                avatarText = chat.avatarText;
            }
            
            // 发送消息给父窗口
            try {
                if (window.parent && window.parent !== window) {
                    window.parent.postMessage({
                        type: 'showGlobalNotification',
                        data: {
                            app: '传讯',
                            chatId: chat.id,
                            name: name,
                            message: messageText,
                            avatarData: avatarData,
                            avatarColor: avatarColor,
                            avatarText: avatarText
                        }
                    }, _getPostTargetOrigin());
                } else {
                    // 如果没有父窗口（单独打开），则显示本地通知
                    // 这里保留旧的本地显示逻辑作为后备
                    showLocalChatBubble(chat, messageText);
                }
            } catch (e) {
                console.error('发送全局通知失败', e);
                showLocalChatBubble(chat, messageText);
            }
        }

        // 本地显示的聊天气泡（后备方案）
        function showLocalChatBubble(chat, messageText) {
            // 移除现有的气泡（如果有）
            const existing = document.getElementById('chat-notification-bubble');
            if (existing) existing.remove();
            
            const bubble = document.createElement('div');
            bubble.className = 'chat-bubble';
            bubble.id = 'chat-notification-bubble';
            
            // 获取头像信息
            const contact = appData.contacts.find(c => c.id === chat.contactId);
            let avatarStyle = '';
            let avatarClass = 'chat-bubble-avatar';
            let avatarText = '';
            
            if (contact) {
                if (contact.hasCustomAvatar) {
                    const avatarKey = `avatar_${contact.id}`;
                    const avatarData = localStorage.getItem(avatarKey);
                    if (avatarData) {
                        if (avatarData.startsWith('idb:') && window.ChatStorageDB) {
                            const id = avatarData.slice(4);
                            bubble.setAttribute('data-idb', id);
                        } else {
                            avatarStyle = `background-image: url(${avatarData})`;
                        }
                    } else {
                        avatarClass += ` ${contact.avatarColor}`;
                        avatarText = contact.avatarText;
                    }
                } else {
                    avatarClass += ` ${contact.avatarColor}`;
                    avatarText = contact.avatarText;
                }
            } else {
                avatarClass += ` ${chat.avatarColor}`;
                avatarText = chat.avatarText;
            }
            
            const name = contact ? contact.name : chat.name;
            
            // 处理消息内容长度
            let displayMessage = messageText;
            if (displayMessage.length > 20) {
                displayMessage = displayMessage.substring(0, 20) + '...';
            }
            
            bubble.innerHTML = `
                <div class="${avatarClass}" style="${avatarStyle}">${avatarText}</div>
                <div class="chat-bubble-content">
                    <div class="chat-bubble-name">${name}</div>
                    <div class="chat-bubble-text">${escapeHtml(displayMessage)}</div>
                </div>
            `;

            const bubbleId = bubble.getAttribute('data-idb');
            if (bubbleId && window.ChatStorageDB) {
                const avatarEl = bubble.querySelector('.chat-bubble-avatar');
                window.ChatStorageDB.get(bubbleId).then(storedValue => {
                    if (!storedValue || !avatarEl || !document.body.contains(bubble)) return;
                    let src = '';
                    if (typeof storedValue === 'string') {
                        src = storedValue;
                    } else if (typeof URL !== 'undefined' && typeof URL.createObjectURL === 'function') {
                        src = URL.createObjectURL(storedValue);
                        bubble.setAttribute('data-temp-url', src);
                    }
                    if (!src) return;
                    avatarEl.style.backgroundImage = `url(${src})`;
                    avatarEl.textContent = '';
                }).catch(() => {});
            }
            
            // 点击跳转到聊天页
            bubble.addEventListener('click', () => {
                openDialogue(chat.id);
                bubble.classList.add('hide');
                setTimeout(() => {
                    const tempUrl = bubble.getAttribute('data-temp-url');
                    if (tempUrl) {
                        revokeBlobUrl(tempUrl);
                    }
                    bubble.remove();
                }, 300);
            });
            
            document.body.appendChild(bubble);
            
            // 5秒后自动消失
            setTimeout(() => {
                if (document.body.contains(bubble)) {
                    bubble.classList.add('hide');
                    setTimeout(() => {
                        const tempUrl = bubble.getAttribute('data-temp-url');
                        if (tempUrl && typeof URL !== 'undefined' && typeof URL.revokeObjectURL === 'function') {
                            try { URL.revokeObjectURL(tempUrl); } catch (e) {}
                        }
                        bubble.remove();
                    }, 300);
                }
            }, 5000);
        }
        
        // ==================== 个人资料编辑功能 ====================
        
        const profileManager = {
            selectedColor: 'bg-sage',
            avatarImage: null,
            
            init: function() {
                this.setupEventListeners();
                this.loadUserProfile();
            },
            
            loadUserProfile: function() {
                const user = appData.currentUser;
                this.updateProfileDisplay(user);
            },
            
            updateProfileDisplay: async function(user) {
                const avatarElement = document.getElementById('profile-avatar');
                const nameElement = document.getElementById('profile-name-text');
                const wechatIdElement = document.getElementById('profile-wechat-id-text');
                
                nameElement.textContent = user.name;
                wechatIdElement.textContent = user.wechatId;
                
                if (user.hasCustomAvatar) {
                    const avatarKey = 'user_avatar';
                    const avatarData = localStorage.getItem(avatarKey);
                    if (avatarData) {
                        avatarElement.className = 'profile-avatar has-custom';
                        setElementImageFromStore(avatarElement, avatarData);
                        avatarElement.innerHTML = '<div class="avatar-edit-overlay">点击修改</div>';
                        return;
                    }
                }

                avatarElement.className = `profile-avatar ${user.avatarColor}`;
                setElementImageFromStore(avatarElement, '');
                avatarElement.innerHTML = `${user.name.charAt(0).toUpperCase()}<div class="avatar-edit-overlay">点击修改</div>`;
            },
            
            setupEventListeners: function() {
                document.getElementById('profile-avatar').addEventListener('click', () => {
                    this.openEditDialog();
                });
                
                document.getElementById('profile-name').addEventListener('click', () => {
                    this.openEditDialog();
                });
                
                document.getElementById('profile-wechat-id').addEventListener('click', () => {
                    this.openEditDialog();
                });
                
                document.getElementById('profile-edit-cancel').addEventListener('click', () => {
                    this.closeEditDialog();
                });
                
                document.getElementById('profile-edit-save').addEventListener('click', () => {
                    this.saveProfile();
                });
                
                document.getElementById('profile-edit-avatar-preview').addEventListener('click', () => {
                    document.getElementById('profile-edit-upload').click();
                });
                
                document.getElementById('profile-edit-upload').addEventListener('change', (e) => {
                    this.handleAvatarUpload(e);
                });
                
                document.querySelectorAll('.profile-color-option').forEach(option => {
                    option.addEventListener('click', (e) => {
                        this.selectAvatarColor(e.target.dataset.color);
                    });
                });
                
                document.addEventListener('keydown', (e) => {
                    if (e.key === 'Escape' && document.getElementById('profile-edit-dialog').classList.contains('show')) {
                        this.closeEditDialog();
                    }
                });
            },
            
            openEditDialog: function() {
                const user = appData.currentUser;
                const dialog = document.getElementById('profile-edit-dialog');
                
                document.getElementById('profile-name-input').value = user.name;
                document.getElementById('profile-wechat-id-input').value = user.wechatId;
                
                this.updateAvatarPreview(user);
                this.selectAvatarColor(user.avatarColor);
                
                dialog.classList.add('show');
                safeLockScroll();
                
                setTimeout(() => {
                    document.getElementById('profile-name-input').focus();
                }, 300);
            },
            
            closeEditDialog: function() {
                document.getElementById('profile-edit-dialog').classList.remove('show');
                safeUnlockScroll();
                this.avatarImage = null;
            },
            
            updateAvatarPreview: async function(user) {
                const preview = document.getElementById('profile-edit-avatar-preview');
                const text = document.getElementById('profile-edit-avatar-text');
                
                text.textContent = user.name.charAt(0).toUpperCase();
                
                if (user.hasCustomAvatar) {
                    const avatarKey = 'user_avatar';
                    const avatarData = localStorage.getItem(avatarKey);
                    if (avatarData) {
                        preview.className = 'profile-edit-avatar has-custom';
                        setElementImageFromStore(preview, avatarData);
                        text.style.display = 'none';
                    } else {
                        preview.className = `profile-edit-avatar ${user.avatarColor}`;
                        setElementImageFromStore(preview, '');
                        text.style.display = 'flex';
                    }
                } else {
                    preview.className = `profile-edit-avatar ${user.avatarColor}`;
                    setElementImageFromStore(preview, '');
                    text.style.display = 'flex';
                }
                
                if (this.avatarImage) {
                    preview.className = 'profile-edit-avatar has-custom';
                    setElementImageFromStore(preview, this.avatarImage);
                    text.style.display = 'none';
                }
            },
            
            selectAvatarColor: function(color) {
                this.selectedColor = color;
                
                document.querySelectorAll('.profile-color-option').forEach(option => {
                    if (option.dataset.color === color) {
                        option.classList.add('selected');
                    } else {
                        option.classList.remove('selected');
                    }
                });
                
                if (!this.avatarImage) {
                    const preview = document.getElementById('profile-edit-avatar-preview');
                    const user = appData.currentUser;
                    
                    if (!user.hasCustomAvatar) {
                        preview.className = `profile-edit-avatar ${color}`;
                        preview.style.backgroundImage = '';
                        
                        const text = document.getElementById('profile-edit-avatar-text');
                        text.style.display = 'flex';
                        text.textContent = user.name.charAt(0).toUpperCase();
                    }
                }
            },
            
            handleAvatarUpload: function(event) {
                const file = event.target.files[0];
                if (!file) return;
                
                if (!file.type.match('image.*')) {
                    showNotification('请选择图片文件', 'error');
                    return;
                }
                
                const reader = new FileReader();
                reader.onload = (e) => {
                    compressImage(e.target.result, 512, 0.82).then(compressedDataUrl => {
                        this.avatarImage = compressedDataUrl;
                        this.updateAvatarPreview(appData.currentUser);
                        showNotification('头像已选择，点击保存应用', 'info');
                    }).catch(err => {
                        console.error('Image compression failed:', err);
                        this.avatarImage = e.target.result;
                        this.updateAvatarPreview(appData.currentUser);
                        showNotification('头像已选择 (未压缩)', 'info');
                    });
                };
                
                reader.onerror = () => {
                    showNotification('读取图片失败', 'error');
                };
                
                reader.readAsDataURL(file);
            },
            
            saveProfile: async function() {
                const nameInput = document.getElementById('profile-name-input');
                const wechatIdInput = document.getElementById('profile-wechat-id-input');
                
                const name = nameInput.value.trim();
                const wechatId = wechatIdInput.value.trim();
                
                if (!name) {
                    showNotification('昵称不能为空', 'error');
                    return;
                }
                
                if (name.length > 20) {
                    showNotification('昵称不能超过20个字符', 'error');
                    return;
                }
                
                if (!wechatId) {
                    showNotification('微信号不能为空', 'error');
                    return;
                }
                
                if (wechatId.length > 30) {
                    showNotification('微信号不能超过30个字符', 'error');
                    return;
                }
                
                const user = appData.currentUser;
                const oldName = user.name;
                
                user.name = name;
                user.wechatId = wechatId;
                
                // 修复：用户自定义头像保存问题
                if (this.avatarImage) {
                    user.hasCustomAvatar = true;
                    user.avatarColor = this.selectedColor;
                    
                    try {
                        const id = `user_avatar_${Date.now()}`;
                        await window.ChatStorageDB.put(id, this.avatarImage, 'image');
                        localStorage.setItem('user_avatar', `idb:${id}`);
                        console.log('用户头像已保存到IndexedDB');
                    } catch (error) {
                        console.error('保存头像失败:', error);
                        showNotification('保存头像失败: ' + error.message, 'error');
                        return;
                    }
                    
                    this.avatarImage = null;
                } else if (this.selectedColor !== user.avatarColor) {
                    user.avatarColor = this.selectedColor;
                    user.hasCustomAvatar = false;
                    
                    localStorage.removeItem('user_avatar');
                }
                
                await saveData();
                this.updateProfileDisplay(user);
                
                if (oldName !== name) {
                    appData.chats.forEach(chat => {
                        chat.messages.forEach(msg => {
                            if (msg.sender === 'me' && msg.senderName === oldName) {
                                msg.senderName = name;
                            }
                        });
                    });
                    
                    saveData();
                }

                if (appData.currentDialogue) {
                    loadDialogueMessages(appData.currentDialogue);
                }
                
                this.closeEditDialog();
                showNotification('个人资料已更新', 'success');
            }
        };
        
        // ==================== 设置页面功能 ====================

        const uiDialog = {
            state: {
                isOpen: false,
                resolver: null,
                mode: 'confirm',
                multiline: false,
                previousActiveElement: null
            },
            init: function() {
                const dialog = document.getElementById('uiDialog');
                if (!dialog) return;

                const cancelBtn = document.getElementById('uiDialogCancel');
                const confirmBtn = document.getElementById('uiDialogConfirm');

                dialog.addEventListener('click', (e) => {
                    if (e.target === dialog) this.close(null);
                });

                cancelBtn.addEventListener('click', () => this.close(null));
                confirmBtn.addEventListener('click', () => this.confirm());

                const quickActions = document.getElementById('uiDialogQuickActions');
                if (quickActions) {
                    quickActions.querySelectorAll('.quick-action-btn').forEach(btn => {
                        btn.addEventListener('click', () => {
                            const type = btn.getAttribute('data-type');
                            const activeEl = this.state.multiline 
                                ? document.getElementById('uiDialogTextarea') 
                                : document.getElementById('uiDialogInput');
                            if (!activeEl) return;

                            const start = activeEl.selectionStart;
                            const end = activeEl.selectionEnd;
                            const val = activeEl.value;
                            const selectedText = val.substring(start, end);
                            
                            let newText = '';
                            if (type === 'system') {
                                if (selectedText) {
                                    newText = val.substring(0, start) + `[系统] ${selectedText}` + val.substring(end);
                                } else {
                                    newText = val.substring(0, start) + `[系统] ` + val.substring(end);
                                }
                            } else if (type === 'voice') {
                                if (selectedText) {
                                    newText = val.substring(0, start) + `{{voice}}${selectedText}` + val.substring(end);
                                } else {
                                    newText = val.substring(0, start) + `{{voice}}` + val.substring(end);
                                }
                            } else if (type === 'split') {
                                newText = val.substring(0, start) + '\n---\n' + val.substring(end);
                            }

                            if (newText) {
                                activeEl.value = newText;
                                activeEl.focus();
                                // 设置光标位置
                                let newPos;
                                if (type === 'system') {
                                    newPos = start + 5;
                                } else if (type === 'voice') {
                                    newPos = start + 9;
                                } else if (type === 'split') {
                                    newPos = start + 5;
                                }
                                activeEl.setSelectionRange(newPos, newPos);
                            }
                        });
                    });
                }

                document.addEventListener('keydown', (e) => {
                    if (!this.state.isOpen) return;
                    if (e.key === 'Escape') {
                        e.preventDefault();
                        this.close(null);
                        return;
                    }
                    if (e.key === 'Enter') {
                        if (this.state.mode === 'prompt') {
                            if (this.state.multiline) {
                                if (e.ctrlKey || e.metaKey) {
                                    e.preventDefault();
                                    this.confirm();
                                }
                                return;
                            }
                            const input = document.getElementById('uiDialogInput');
                            if (document.activeElement === input) {
                                e.preventDefault();
                                this.confirm();
                            }
                        } else {
                            e.preventDefault();
                            this.confirm();
                        }
                    }
                });
            },
            openConfirm: function(opts) {
                return this.open({
                    title: opts && opts.title ? opts.title : '确认',
                    message: opts && opts.message ? opts.message : '',
                    confirmText: opts && opts.confirmText ? opts.confirmText : '确定',
                    cancelText: opts && opts.cancelText ? opts.cancelText : '取消',
                    mode: 'confirm'
                });
            },
            openPrompt: function(opts) {
                return this.open({
                    title: opts && opts.title ? opts.title : '请输入',
                    message: opts && opts.message ? opts.message : '',
                    confirmText: opts && opts.confirmText ? opts.confirmText : '确定',
                    cancelText: opts && opts.cancelText ? opts.cancelText : '取消',
                    mode: 'prompt',
                    multiline: !!(opts && opts.multiline),
                    initialValue: opts && typeof opts.initialValue === 'string' ? opts.initialValue : '',
                    placeholder: opts && typeof opts.placeholder === 'string' ? opts.placeholder : '',
                    maxLength: opts && typeof opts.maxLength === 'number' ? opts.maxLength : null,
                    showFormatRepair: !!(opts && opts.showFormatRepair)
                });
            },
            open: function(opts) {
                const dialog = document.getElementById('uiDialog');
                const title = document.getElementById('uiDialogTitle');
                const message = document.getElementById('uiDialogMessage');
                const input = document.getElementById('uiDialogInput');
                const textarea = document.getElementById('uiDialogTextarea');
                const quickActions = document.getElementById('uiDialogQuickActions');
                const cancelBtn = document.getElementById('uiDialogCancel');
                const confirmBtn = document.getElementById('uiDialogConfirm');
                if (!dialog || !title || !message || !input || !textarea || !cancelBtn || !confirmBtn) {
                    return Promise.resolve(null);
                }

                this.state.mode = opts.mode;
                this.state.multiline = !!opts.multiline;

                this.state.previousActiveElement = document.activeElement;

                title.textContent = String(opts.title || '');
                message.textContent = String(opts.message || '');
                cancelBtn.textContent = String(opts.cancelText || '取消');
                confirmBtn.textContent = String(opts.confirmText || '确定');

                confirmBtn.classList.remove('danger');
                if (opts && opts.variant === 'danger') {
                    confirmBtn.classList.add('danger');
                }

                input.style.display = 'none';
                textarea.style.display = 'none';
                if (quickActions) quickActions.style.display = 'none';

                if (opts.mode === 'prompt') {
                    const activeEl = opts.multiline ? textarea : input;
                    activeEl.style.display = 'block';
                    activeEl.value = String(opts.initialValue || '');
                    activeEl.placeholder = String(opts.placeholder || '');
                    if (opts.maxLength != null) {
                        activeEl.maxLength = opts.maxLength;
                    } else {
                        activeEl.removeAttribute('maxlength');
                    }

                    if (quickActions && opts.showFormatRepair) {
                        const currentChatId = appData.currentDialogue;
                        let chatMode = 'card';
                        if (currentChatId && window.chat20 && window.chat20.state.friendPersonaSettings) {
                            const chat = appData.chats.find(c => c.id === currentChatId);
                            if (chat && window.chat20.state.friendPersonaSettings[chat.contactId]) {
                                chatMode = window.chat20.state.friendPersonaSettings[chat.contactId].chatMode || 'card';
                            }
                        }

                        if (chatMode === 'ai_chat' || chatMode === 'ai_card') {
                            quickActions.style.display = 'flex';
                        } else {
                            quickActions.style.display = 'none';
                        }
                    }
                }

                dialog.classList.add('show');
                dialog.setAttribute('aria-hidden', 'false');
                this.state.isOpen = true;

                safeLockScroll();

                setTimeout(function() {
                    if (opts.mode === 'prompt') {
                        const activeEl = opts.multiline ? textarea : input;
                        activeEl.focus();
                        activeEl.select();
                    } else {
                        confirmBtn.focus();
                    }
                }, 0);

                return new Promise((resolve) => {
                    this.state.resolver = resolve;
                });
            },
            confirm: function() {
                if (this.state.mode === 'prompt') {
                    const activeEl = this.state.multiline 
                        ? document.getElementById('uiDialogTextarea') 
                        : document.getElementById('uiDialogInput');
                    const v = activeEl ? String(activeEl.value || '').trim() : '';
                    this.close(v);
                } else {
                    this.close(true);
                }
            },
            close: function(result) {
                const dialog = document.getElementById('uiDialog');
                if (dialog) {
                    dialog.classList.remove('show');
                    dialog.setAttribute('aria-hidden', 'true');
                }
                this.state.isOpen = false;
                const resolve = this.state.resolver;
                this.state.resolver = null;
                if (typeof resolve === 'function') resolve(result);

                safeUnlockScroll();

                const el = this.state.previousActiveElement;
                this.state.previousActiveElement = null;
                if (el && typeof el.focus === 'function') {
                    setTimeout(() => el.focus(), 0);
                }
            }
        };
        
        window.AIService = {
            storageKey: 'ai_service_config',
            
            _loadData: function() {
                try {
                    const raw = localStorage.getItem(this.storageKey);
                    let data = raw ? JSON.parse(raw) : null;
                    
                    if (!data || !data.profiles) {
                        const fallback = data && typeof data === 'object' ? data : {};
                        const defaultProfile = {
                            id: 'default',
                            name: '默认配置',
                            url: fallback.url || '',
                            key: fallback.key || '',
                            model: fallback.model || '',
                            enabled: !!fallback.enabled,
                            lastStatus: 'disconnected'
                        };
                        data = {
                            activeId: 'default',
                            profiles: [defaultProfile]
                        };
                        this._saveData(data);
                    }
                    return data;
                } catch (e) {
                    console.error('Failed to load AI settings', e);
                    return {
                        activeId: 'default',
                        profiles: [{ id: 'default', name: '默认配置', url: '', key: '', model: '', enabled: false }]
                    };
                }
            },

            _saveData: function(data) {
                localStorage.setItem(this.storageKey, JSON.stringify(data));
            },

            _defaultUsage: function() {
                return {
                    totalRequests: 0,
                    totalPromptTokens: 0,
                    totalCompletionTokens: 0,
                    totalTokens: 0,
                    testRequests: 0,
                    lastUsedAt: 0
                };
            },

            _loadUsage: function(profileId) {
                const data = this._loadData();
                const id = profileId || data.activeId;
                const profile = data.profiles.find(p => p.id === id) || data.profiles[0];
                if (!profile) return this._defaultUsage();
                const u = profile.usage && typeof profile.usage === 'object' ? profile.usage : {};
                const base = this._defaultUsage();
                return {
                    totalRequests: Number(u.totalRequests) || base.totalRequests,
                    totalPromptTokens: Number(u.totalPromptTokens) || base.totalPromptTokens,
                    totalCompletionTokens: Number(u.totalCompletionTokens) || base.totalCompletionTokens,
                    totalTokens: Number(u.totalTokens) || base.totalTokens,
                    testRequests: Number(u.testRequests) || base.testRequests,
                    lastUsedAt: Number(u.lastUsedAt) || base.lastUsedAt
                };
            },

            _saveUsage: function(profileId, usage) {
                const data = this._loadData();
                const id = profileId || data.activeId;
                const idx = data.profiles.findIndex(p => p.id === id);
                if (idx === -1) return;
                data.profiles[idx].usage = Object.assign(this._defaultUsage(), usage || {});
                this._saveData(data);
            },

            recordUsage: function(apiResponse, profileId, options) {
                const isTest = options && options.isTest;
                const prev = this._loadUsage(profileId);
                const next = {
                    totalRequests: prev.totalRequests + 1,
                    totalPromptTokens: prev.totalPromptTokens,
                    totalCompletionTokens: prev.totalCompletionTokens,
                    totalTokens: prev.totalTokens,
                    testRequests: prev.testRequests + (isTest ? 1 : 0),
                    lastUsedAt: Date.now()
                };

                if (apiResponse && apiResponse.usage && typeof apiResponse.usage === 'object') {
                    const u = apiResponse.usage;
                    const pt = Number(u.prompt_tokens) || 0;
                    const ct = Number(u.completion_tokens) || 0;
                    const tt = Number(u.total_tokens) || (pt + ct);
                    next.totalPromptTokens += pt;
                    next.totalCompletionTokens += ct;
                    next.totalTokens += tt;
                }

                this._saveUsage(profileId, next);
            },
            
            _detectProvider: function(settings) {
                if (!settings || !settings.url) return 'other';
                var url = String(settings.url).toLowerCase();
                if (url.includes('anthropic') || url.includes('claude')) return 'anthropic';
                if (url.includes('openai') || url.includes('api.openai')) return 'openai';
                return 'other';
            },
            
            _recordJournal: function(apiResponse, contextInfo) {
                if (!window.ApiJournalStore) return;
                
                var inputTokens = 0;
                var outputTokens = 0;
                var totalTokens = 0;
                var isEstimated = true;
                
                if (apiResponse && apiResponse.usage && typeof apiResponse.usage === 'object') {
                    var u = apiResponse.usage;
                    inputTokens = Number(u.prompt_tokens) || Number(u.input_tokens) || 0;
                    outputTokens = Number(u.completion_tokens) || Number(u.output_tokens) || 0;
                    totalTokens = Number(u.total_tokens) || (inputTokens + outputTokens);
                    isEstimated = false;
                }
                
                var record = {
                    timestamp: contextInfo.startTime || Date.now(),
                    friendId: contextInfo.friendId || null,
                    purpose: contextInfo.purpose || 'other',
                    model: contextInfo.model || 'unknown',
                    provider: contextInfo.provider || 'other',
                    apiProfileId: contextInfo.apiProfileId || null,
                    apiConfigName: contextInfo.apiConfigName || 'unknown',
                    inputTokens: inputTokens,
                    outputTokens: outputTokens,
                    totalTokens: totalTokens,
                    isEstimated: isEstimated,
                    requestDuration: Date.now() - (contextInfo.startTime || Date.now()),
                    success: contextInfo.success !== false,
                    httpStatus: contextInfo.httpStatus || null,
                    errorMessage: contextInfo.errorMessage || null
                };
                
                window.ApiJournalStore.record(record);
            },

            getUsageSummary: function(profileId) {
                return this._loadUsage(profileId);
            },

            resetUsage: function(profileId) {
                this._saveUsage(profileId, this._defaultUsage());
            },

            getSettings: function() {
                const data = this._loadData();
                return data.profiles.find(p => p.id === data.activeId) || data.profiles[0];
            },
            
            saveSettings: function(settings) {
                const data = this._loadData();
                const index = data.profiles.findIndex(p => p.id === data.activeId);
                if (index !== -1) {
                    data.profiles[index] = { ...data.profiles[index], ...settings };
                    this._saveData(data);
                }
            },

            getProfiles: function() {
                return this._loadData();
            },

            setActiveProfile: function(id) {
                const data = this._loadData();
                if (data.profiles.some(p => p.id === id)) {
                    data.activeId = id;
                    this._saveData(data);
                    return true;
                }
                return false;
            },

            addProfile: function(name, initialSettings = {}) {
                const data = this._loadData();
                const newId = 'profile_' + Date.now();
                const newProfile = {
                    id: newId,
                    name: name,
                    url: initialSettings.url || '',
                    key: initialSettings.key || '',
                    model: initialSettings.model || '',
                    enabled: initialSettings.enabled || false,
                    lastStatus: initialSettings.lastStatus || 'disconnected',
                    instructMode: initialSettings.instructMode || 'none',
                    customUserPrefix: initialSettings.customUserPrefix || '',
                    customAssistantPrefix: initialSettings.customAssistantPrefix || '',
                    temp: typeof initialSettings.temp === 'number' ? initialSettings.temp : undefined,
                    maxTokens: typeof initialSettings.maxTokens === 'number' ? initialSettings.maxTokens : undefined,
                    topP: typeof initialSettings.topP === 'number' ? initialSettings.topP : undefined,
                    freqPenalty: typeof initialSettings.freqPenalty === 'number' ? initialSettings.freqPenalty : undefined,
                    contextSize: typeof initialSettings.contextSize === 'number' ? initialSettings.contextSize : undefined,
                    usage: this._defaultUsage()
                };
                data.profiles.push(newProfile);
                data.activeId = newId;
                this._saveData(data);
                return newId;
            },

            deleteProfile: function(id) {
                const data = this._loadData();
                if (data.profiles.length <= 1) return false;
                
                const index = data.profiles.findIndex(p => p.id === id);
                if (index === -1) return false;

                data.profiles.splice(index, 1);
                
                if (data.activeId === id) {
                    data.activeId = data.profiles[0].id;
                }
                
                this._saveData(data);
                return true;
            },

            renameProfile: function(id, newName) {
                const data = this._loadData();
                const profile = data.profiles.find(p => p.id === id);
                if (profile) {
                    profile.name = newName;
                    this._saveData(data);
                    return true;
                }
                return false;
            },
            
            _fixUrl: function(base, suffix) {
                const url = String(base || '').trim();
                if (!url) return '';
                if (url.includes(suffix)) return url;
                if (url.includes('/messages') || url.includes('/completions')) return url;
                if (url.endsWith('/v1') || url.endsWith('/v1/')) {
                    return url.replace(/\/+$/, '') + suffix;
                }
                return url.replace(/\/+$/, '') + '/v1' + suffix;
            },

            _extractContent: function(payload) {
                if (!payload) return '';
                if (typeof payload === 'string') return payload;
                const choices = Array.isArray(payload.choices) ? payload.choices : [];
                if (choices.length > 0) {
                    const first = choices[0] || {};
                    const msg = first.message || {};
                    const delta = first.delta || {};
                    const text = msg.content || first.text || delta.content;
                    if (text) return text;
                }
                if (payload.output_text) return payload.output_text;
                if (payload.output && typeof payload.output === 'string') return payload.output;
                if (payload.output && payload.output.text) return payload.output.text;
                if (payload.result) return payload.result;
                if (payload.message && payload.message.content) return payload.message.content;
                if (payload.content) {
                    if (typeof payload.content === 'string') return payload.content;
                    if (Array.isArray(payload.content)) {
                        const firstText = payload.content.find(item => item && item.text);
                        if (firstText && firstText.text) return firstText.text;
                    }
                }
                if (payload.data && payload.data.choices && Array.isArray(payload.data.choices)) {
                    const first = payload.data.choices[0] || {};
                    const msg = first.message || {};
                    const text = msg.content || first.text;
                    if (text) return text;
                }
                return '';
            },

            _detectProvider: function(settings) {
                const url = settings && settings.url ? String(settings.url).toLowerCase() : '';
                const model = settings && settings.model ? String(settings.model).toLowerCase() : '';
                if (url.includes('anthropic') || url.includes('/messages') || model.startsWith('claude')) return 'anthropic';
                return 'openai';
            },

            _buildRequest: function(settings, messages, options) {
                const provider = this._detectProvider(settings);
                const url = settings.url || '';
                const key = settings.key || '';
                const model = settings.model || '';
                const list = Array.isArray(messages) ? messages : [];
                
                // 修复：验证必要参数
                if (!url) {
                    throw new Error('API URL未配置');
                }
                if (!key) {
                    throw new Error('API密钥未配置');
                }
                if (!model && provider !== 'anthropic') {
                    // Anthropic可能不需要model（使用默认），但OpenAI需要
                    throw new Error('模型名称未配置：请在API管理中配置模型');
                }
                
                // Advanced Settings from Profile or Friend-level overrides
                var tempRaw = options.temperature !== undefined ? options.temperature : (settings.temp !== undefined ? settings.temp : 0.7);
                var temp = Number(tempRaw);
                if (!Number.isFinite(temp)) temp = 0.7;
                temp = Math.max(0, Math.min(2, temp));
                
                var maxTokensRaw = options.max_tokens !== undefined ? options.max_tokens : (settings.maxTokens !== undefined ? settings.maxTokens : undefined);
                var maxTokens = maxTokensRaw !== undefined ? Number(maxTokensRaw) : undefined;
                if (maxTokens !== undefined && !Number.isFinite(maxTokens)) maxTokens = undefined;
                
                var topPRaw = options.topP !== undefined ? options.topP : (settings.topP !== undefined ? settings.topP : 1.0);
                var topP = Number(topPRaw);
                if (!Number.isFinite(topP)) topP = 1.0;
                topP = Math.max(0, Math.min(1, topP));
                
                var freqPenaltyRaw = options.freqPenalty !== undefined ? options.freqPenalty : (settings.freqPenalty !== undefined ? settings.freqPenalty : 0);
                var freqPenalty = Number(freqPenaltyRaw);
                if (!Number.isFinite(freqPenalty)) freqPenalty = 0;
                freqPenalty = Math.max(-2, Math.min(2, freqPenalty));
                
                // Instruct Mode / Custom Prefix Logic
                let processedMessages = list;
                if (settings.instructMode === 'custom') {
                    const userPrefix = settings.customUserPrefix || '';
                    const assistantPrefix = settings.customAssistantPrefix || '';
                    
                    if (userPrefix || assistantPrefix) {
                        processedMessages = list.map(msg => {
                            if (msg.role === 'user' && userPrefix) {
                                return { ...msg, content: `${userPrefix}\n${msg.content}` };
                            }
                            if (msg.role === 'assistant' && assistantPrefix) {
                                return { ...msg, content: `${assistantPrefix}\n${msg.content}` };
                            }
                            return msg;
                        });
                    }
                } else if (settings.instructMode === 'alpaca') {
                     // Simple Alpaca Style Injection
                     processedMessages = list.map(msg => {
                        if (msg.role === 'user') return { ...msg, content: `### Instruction:\n${msg.content}\n\n### Response:` };
                        return msg;
                    });
                } else if (settings.instructMode === 'vicuna') {
                    // Vicuna Style
                    processedMessages = list.map(msg => {
                        if (msg.role === 'user') return { ...msg, content: `USER: ${msg.content}\nASSISTANT:` };
                        return msg;
                    });
                } else if (settings.instructMode === 'chatml') {
                    // ChatML is usually handled by the tokenizer/backend, but if we must force it:
                    // We typically don't modify content for ChatML in OpenAI API as the 'role' handles it.
                    // Leaving as is for compatibility.
                }

                if (provider === 'anthropic') {
                    let systemText = '';
                    const mapped = [];
                    processedMessages.forEach(item => {
                        const role = item && item.role ? item.role : 'user';
                        const content = item && item.content != null ? String(item.content) : '';
                        if (role === 'system') {
                            if (content) systemText = systemText ? (systemText + '\n\n' + content) : content;
                        } else if (role === 'assistant' || role === 'user') {
                            mapped.push({ role: role, content: content });
                        } else {
                            mapped.push({ role: 'user', content: content });
                        }
                    });
                    const body = {
                        model: model || 'claude-3-haiku-20240307',
                        max_tokens: Number.isFinite(maxTokens) ? maxTokens : 4096,
                        temperature: temp,
                        top_p: topP,
                        messages: mapped
                    };
                    if (systemText) body.system = systemText;
                    return {
                        url: this._fixUrl(url, '/messages'),
                        headers: {
                            'Content-Type': 'application/json',
                            'x-api-key': key,
                            'anthropic-version': '2023-06-01'
                        },
                        body
                    };
                }

                const body = {
                    model: model || 'gpt-3.5-turbo',
                    messages: processedMessages,
                    temperature: temp,
                    top_p: topP,
                    frequency_penalty: freqPenalty
                };
                if (Number.isFinite(maxTokens)) body.max_tokens = maxTokens;
                return {
                    url: this._fixUrl(url, '/chat/completions'),
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${key}`
                    },
                    body
                };
            },

            testConnection: async function(settings) {
                const { url, key, model } = settings;
                if (!url || !key) throw new Error('URL或密钥为空');

                // 修复4：增强浏览器兼容性检测
                if (!window.fetch) {
                    throw new Error('当前浏览器不支持网络请求（fetch API不可用），请更换浏览器或关闭AI功能');
                }

                let controller = null;
                let timeoutId = null;
                let signal = undefined;
                if (typeof AbortController !== 'undefined') {
                    controller = new AbortController();
                    signal = controller.signal;
                    timeoutId = setTimeout(function() {
                        try {
                            controller.abort();
                        } catch (e) {}
                    }, 10000);
                }

                try {
                    const request = this._buildRequest({ url, key, model }, [{ role: 'user', content: 'Hi' }], { temperature: 0, max_tokens: 1 });
                    const response = await fetch(request.url, {
                        method: 'POST',
                        headers: request.headers,
                        body: JSON.stringify(request.body),
                        signal: signal
                    });
                    
                    if (timeoutId != null) {
                        clearTimeout(timeoutId);
                    }

                    if (!response.ok) {
                        const errText = await response.text();
                        // 修复4：详细的错误信息
                        let errorMsg = `HTTP ${response.status}`;
                        if (response.status === 401) {
                            errorMsg = '认证失败：API密钥无效或已过期';
                        } else if (response.status === 403) {
                            errorMsg = '访问被拒绝：请检查API密钥权限';
                        } else if (response.status === 404) {
                            errorMsg = '接口地址不存在：请检查URL是否正确';
                        } else if (response.status >= 500) {
                            errorMsg = `服务器错误（${response.status}）：API服务暂时不可用`;
                        } else {
                            errorMsg = `请求失败（${response.status}）：${errText.slice(0, 100)}`;
                        }
                        throw new Error(errorMsg);
                    }

                    const data = await response.json();
                    this.recordUsage(data, null, { isTest: true });
                    this.saveSettings({ lastStatus: 'connected' });
                    return data;
                } catch (e) {
                    if (timeoutId != null) {
                        clearTimeout(timeoutId);
                    }
                    this.saveSettings({ lastStatus: 'error' });
                    
                    // 修复4：区分不同类型的错误
                    if (e.name === 'AbortError' || e.message && e.message.includes('aborted')) {
                        throw new Error('连接超时：请检查网络连接或API服务是否可访问');
                    } else if (e.message && (e.message.includes('Failed to fetch') || e.message.includes('NetworkError'))) {
                        throw new Error('网络错误：无法连接到API服务器（常见原因：跨域CORS限制、网络不通或代理设置问题）');
                    } else if (e.message && e.message.includes('CORS')) {
                        throw new Error('跨域错误：API服务器未允许当前域名访问（CORS限制）');
                    } else if (e.message) {
                        throw e;
                    } else {
                        throw new Error(`连接失败：${String(e)}`);
                    }
                }
            },

            fetchModels: async function(settings) {
                const { url, key } = settings;
                if (!url || !key) throw new Error('URL或密钥为空');
                const provider = this._detectProvider(settings);
                if (provider === 'anthropic') {
                    return settings.model ? [{ id: settings.model }] : [];
                }
                const fetchUrl = this._fixUrl(url, '/models');

                if (!window.fetch) {
                    throw new Error('当前浏览器不支持网络请求（fetch API不可用），请更换浏览器或关闭AI功能');
                }

                // 修复4：添加超时处理
                let controller = null;
                let timeoutId = null;
                let signal = undefined;
                if (typeof AbortController !== 'undefined') {
                    controller = new AbortController();
                    signal = controller.signal;
                    timeoutId = setTimeout(function() {
                        try {
                            controller.abort();
                        } catch (e) {}
                    }, 15000); // 15秒超时
                }

                try {
                    const response = await fetch(fetchUrl, {
                        method: 'GET',
                        headers: {
                            'Content-Type': 'application/json',
                            'Authorization': `Bearer ${key}`
                        },
                        signal: signal
                    });

                    if (timeoutId != null) {
                        clearTimeout(timeoutId);
                    }

                    if (!response.ok) {
                        const errText = await response.text();
                        let errorMsg = `HTTP ${response.status}`;
                        if (response.status === 401) {
                            errorMsg = '认证失败：API密钥无效';
                        } else if (response.status === 403) {
                            errorMsg = '访问被拒绝：请检查API密钥权限';
                        } else {
                            errorMsg = `请求失败（${response.status}）：${errText.slice(0, 100)}`;
                        }
                        throw new Error(errorMsg);
                    }

                    const data = await response.json();
                    this.recordUsage(data);
                    this.saveSettings({ lastStatus: 'connected' });
                    return data.data || [];
                } catch (e) {
                    if (timeoutId != null) {
                        clearTimeout(timeoutId);
                    }
                    this.saveSettings({ lastStatus: 'error' });
                    
                    // 修复4：区分不同类型的错误
                    if (e.name === 'AbortError' || e.message && e.message.includes('aborted')) {
                        throw new Error('拉取模型列表超时：请检查网络连接');
                    } else if (e.message && (e.message.includes('Failed to fetch') || e.message.includes('NetworkError'))) {
                        throw new Error('网络错误：无法连接到API服务器（可能原因：跨域CORS限制、网络不通）');
                    } else if (e.message && e.message.includes('CORS')) {
                        throw new Error('跨域错误：API服务器未允许当前域名访问');
                    } else if (e.message) {
                        throw e;
                    } else {
                        throw new Error(`拉取模型列表失败：${String(e)}`);
                    }
                }
            },

            // 人设库：保存在 appData.personaLibrary / personaDefaultId 中
            loadPersonaLibrary: async function() {
                try {
                    if (!window.ChatStorageDB || typeof window.ChatStorageDB.getAppData !== 'function') {
                        const raw = localStorage.getItem('chat20.personaLibrary');
                        const defId = localStorage.getItem('chat20.personaDefaultId') || '';
                        const list = raw ? JSON.parse(raw) : [];
                        return { list: Array.isArray(list) ? list : [], defaultId: defId };
                    }
                    const stored = await window.ChatStorageDB.getAppData('personaLibrary');
                    const data = stored && typeof stored === 'object' ? stored : {};
                    const list = Array.isArray(data.list) ? data.list : [];
                    const defId = typeof data.defaultId === 'string' ? data.defaultId : '';
                    return { list, defaultId: defId };
                } catch (e) {
                    console.error('加载人设库失败:', e);
                    return { list: [], defaultId: '' };
                }
            },

            savePersonaLibrary: async function(list, defaultId) {
                const payload = { list: Array.isArray(list) ? list : [], defaultId: defaultId || '' };
                try {
                    if (!window.ChatStorageDB || typeof window.ChatStorageDB.saveAppData !== 'function') {
                        localStorage.setItem('chat20.personaLibrary', JSON.stringify(payload.list));
                        localStorage.setItem('chat20.personaDefaultId', payload.defaultId);
                        return;
                    }
                    await window.ChatStorageDB.saveAppData('personaLibrary', payload);
                } catch (e) {
                    console.error('保存人设库失败:', e);
                }
            },

            generateResponse: async function(messages, options = {}) {
                const startTime = Date.now();
                const friendId = options.friendId || null;
                const purpose = options.purpose || 'other';
                let settings;
                let model = 'unknown';
                let provider = 'other';
                let apiProfileId = null;
                let apiConfigName = 'unknown';
                
                if (options.profileId) {
                    const data = this._loadData();
                    settings = data.profiles.find(p => p.id === options.profileId);
                }
                if (!settings) settings = this.getSettings();
                
                if (!settings) {
                    console.error('[AIService.generateResponse] 配置不存在');
                    throw new Error('AI服务未配置：请先在API管理中配置AI接口');
                }
                
                apiProfileId = settings.id || null;
                apiConfigName = settings.name || 'unknown';
                model = settings.model || 'unknown';
                provider = this._detectProvider(settings);
                
                const { url, key, enabled } = settings;
                
                // 修复：检查enabled字段
                if (enabled === false) {
                    console.warn('[AIService.generateResponse] AI服务已禁用');
                    throw new Error('AI服务已禁用：请在API管理中启用AI服务');
                }
                
                if (!url || !key) {
                    console.error('[AIService.generateResponse] 配置不完整', { url: !!url, key: !!key });
                    throw new Error('AI服务未配置：请先在API管理中配置URL和密钥');
                }

                if (!window.fetch) {
                    throw new Error('当前浏览器不支持网络请求（fetch API不可用），请更换浏览器或关闭AI功能');
                }

                // 修复4：添加超时处理
                let controller = null;
                let timeoutId = null;
                let signal = undefined;
                const timeoutMs = options.timeout || 60000; // 默认60秒超时
                if (typeof AbortController !== 'undefined') {
                    controller = new AbortController();
                    signal = controller.signal;
                    timeoutId = setTimeout(function() {
                        try {
                            controller.abort();
                        } catch (e) {}
                    }, timeoutMs);
                }

                try {
                    const request = this._buildRequest(settings, messages, options);
                    
                    // 修复：添加调试日志
                    if (_debugEnabled) {
                        console.log('[AIService.generateResponse] 请求配置:', {
                            url: request.url,
                            hasHeaders: !!request.headers,
                            hasBody: !!request.body,
                            model: request.body?.model,
                            messageCount: request.body?.messages?.length
                        });
                    }
                    
                    const response = await fetch(request.url, {
                        method: 'POST',
                        headers: request.headers,
                        body: JSON.stringify(request.body),
                        signal: signal
                    });

                    if (timeoutId != null) {
                        clearTimeout(timeoutId);
                    }

                    if (!response.ok) {
                        const errText = await response.text();
                        let errorMsg = `HTTP ${response.status}`;
                        if (response.status === 401) {
                            errorMsg = '认证失败：API密钥无效或已过期';
                        } else if (response.status === 403) {
                            errorMsg = '访问被拒绝：请检查API密钥权限';
                        } else if (response.status === 429) {
                            errorMsg = '请求频率过高：请稍后再试';
                        } else if (response.status >= 500) {
                            errorMsg = `服务器错误（${response.status}）：API服务暂时不可用`;
                        } else {
                            errorMsg = `请求失败（${response.status}）：${errText.slice(0, 100)}`;
                        }
                        throw new Error(errorMsg);
                    }

                    const data = await response.json();
                    this.recordUsage(data);
                    
                    this._recordJournal(data, {
                        friendId: friendId,
                        purpose: purpose,
                        model: model,
                        provider: provider,
                        apiProfileId: apiProfileId,
                        apiConfigName: apiConfigName,
                        startTime: startTime,
                        success: true,
                        httpStatus: response.status
                    });
                    
                    const content = this._extractContent(data);
                    if (content) return content;
                    throw new Error('AI未返回有效内容');
                } catch (e) {
                    if (timeoutId != null) {
                        clearTimeout(timeoutId);
                    }
                    console.error('[AIService.generateResponse] AI Request failed:', e);
                    
                    this._recordJournal(null, {
                        friendId: friendId,
                        purpose: purpose,
                        model: model,
                        provider: provider,
                        apiProfileId: apiProfileId,
                        apiConfigName: apiConfigName,
                        startTime: startTime,
                        success: false,
                        errorMessage: e && e.message ? String(e.message) : String(e)
                    });
                    
                    const errorMessage = e && e.message ? String(e.message) : String(e);
                    
                    if (e.name === 'AbortError' || errorMessage.includes('aborted')) {
                        throw new Error('请求超时：AI响应时间过长（超过60秒），请检查网络连接或稍后重试');
                    } else if (errorMessage.includes('Failed to fetch') || errorMessage.includes('NetworkError') || errorMessage.includes('network')) {
                        throw new Error('网络错误：无法连接到AI服务器\n\n可能原因：\n1. 跨域CORS限制\n2. 网络连接问题\n3. 代理设置问题\n4. API地址不可达\n\n请检查API管理中的URL配置是否正确');
                    } else if (errorMessage.includes('CORS') || errorMessage.includes('cors')) {
                        throw new Error('跨域错误：AI服务器未允许当前域名访问（CORS限制）\n\n请检查API服务器是否配置了正确的CORS头');
                    } else if (errorMessage.includes('API URL未配置') || errorMessage.includes('API密钥未配置') || errorMessage.includes('模型名称未配置')) {
                        throw e; // 直接抛出配置错误
                    } else if (errorMessage.includes('AI服务未配置') || errorMessage.includes('AI服务已禁用')) {
                        throw e; // 直接抛出配置错误
                    } else if (errorMessage) {
                        // 保留原始错误信息，但添加更多上下文
                        throw new Error(`AI请求失败：${errorMessage}\n\n如果问题持续，请检查：\n1. API管理中的URL、密钥、模型是否正确\n2. 网络连接是否正常\n3. API服务是否可用`);
                    } else {
                        throw new Error(`AI请求失败：未知错误（${String(e)}）`);
                    }
                }
            }
        };

        // =====================================================
        // APIVisibilityManager - API 功能显隐控制管理器
        // =====================================================
        window.APIVisibilityManager = {
            // 元素注册表（按类别分组）
            elementRegistry: {
                // "我"标签页入口
                profileEntries: [
                    '#api-management',
                    '#prompt-adjustment',
                    '#persona-management',
                    '#worldbook-management'
                ],
                // 滑动页面
                pages: [
                    '#api-management-page',
                    '#prompt-adjustment-page',
                    '#persona-management-page'
                ],
                // 好友设置页面中的 AI 选项
                friendSettings: [
                    '#friend-ai-section-label',
                    '#friend-my-persona-item',
                    '#friend-persona-item',
                    '#friend-worldbook-item',
                    '#friend-summary-item',
                    '#friend-milestone-item'
                ],
                // 设置页面 AI 格式修复
                settingsItems: [
                    '.ai-format-repair-section'
                ],
                // 聊天模式选择面板中的 AI 模式选项
                chatModeItems: [
                    '.mode-option[data-mode="ai_card"]',
                    '.mode-option[data-mode="ai_chat"]'
                ]
            },

            // 当前模式: 'hidden' | 'full' | 'partial'
            currentMode: 'full',
            
            // 内部状态
            _isEnabled: false,
            _initialized: false,

            /**
             * 初始化管理器，从存储读取状态并应用
             */
            init: function() {
                if (this._initialized) return;
                this._initialized = true;

                // 从 AIService 读取当前启用状态
                this._syncFromAIService();
                
                // 应用当前状态
                this._applyVisibility();
                
                // 设置事件监听
                this._setupListeners();
                
                console.log('[APIVisibilityManager] 初始化完成, enabled:', this._isEnabled);
            },

            /**
             * 从 AIService 同步启用状态
             */
            _syncFromAIService: function() {
                try {
                    if (typeof AIService !== 'undefined' && AIService.getSettings) {
                        const settings = AIService.getSettings();
                        this._isEnabled = !!(settings && settings.enabled);
                    }
                } catch (e) {
                    console.error('[APIVisibilityManager] 同步状态失败:', e);
                    this._isEnabled = false;
                }
            },

            /**
             * 显示所有 API 相关元素
             */
            show: function() {
                this._isEnabled = true;
                this.currentMode = 'full';
                this._applyVisibility();
            },

            /**
             * 隐藏所有 API 相关元素
             */
            hide: function() {
                this._isEnabled = false;
                this.currentMode = 'hidden';
                this._applyVisibility();
            },

            /**
             * 切换显隐状态
             * @param {boolean} enabled - 是否启用
             */
            toggle: function(enabled) {
                this._isEnabled = !!enabled;
                this.currentMode = enabled ? 'full' : 'hidden';
                this._applyVisibility();
            },

            /**
             * 刷新当前状态（重新从 AIService 读取并应用）
             */
            refresh: function() {
                this._syncFromAIService();
                this._applyVisibility();
            },

            /**
             * 设置混合模式（预留接口，支持未来更复杂的显隐逻辑）
             * @param {'hidden'|'full'|'partial'} mode - 显示模式
             * @param {Object} [options] - 可选配置
             */
            setMode: function(mode, options) {
                if (!['hidden', 'full', 'partial'].includes(mode)) {
                    console.warn('[APIVisibilityManager] 无效模式:', mode);
                    return;
                }
                this.currentMode = mode;
                
                // partial 模式下可以指定要显示的类别
                if (mode === 'partial' && options && options.visibleCategories) {
                    this._applyPartialVisibility(options.visibleCategories);
                } else {
                    this._isEnabled = mode !== 'hidden';
                    this._applyVisibility();
                }
            },

            /**
             * 获取当前启用状态
             * @returns {boolean}
             */
            isEnabled: function() {
                return this._isEnabled;
            },

            /**
             * 应用显隐状态到所有注册的元素
             */
            _applyVisibility: function() {
                const show = this._isEnabled;
                
                Object.keys(this.elementRegistry).forEach(category => {
                    const selectors = this.elementRegistry[category];
                    selectors.forEach(selector => {
                        const elements = document.querySelectorAll(selector);
                        elements.forEach(el => {
                            // 修复5.2：确保不会隐藏主内容区
                            if (el.classList && el.classList.contains('main-content')) {
                                return; // 跳过主内容区，永远不隐藏
                            }
                            if (show) {
                                // 显示时，移除强制隐藏，恢复默认或 flex
                                el.style.display = '';
                            } else {
                                // 隐藏时，设置 display: none
                                el.style.display = 'none';
                            }
                        });
                    });
                });

                // 特殊处理：如果禁用，确保相关页面也关闭
                if (!show) {
                    this._closeOpenPages();
                }
            },

            /**
             * 应用部分显示模式
             * @param {string[]} visibleCategories - 要显示的类别数组
             */
            _applyPartialVisibility: function(visibleCategories) {
                const categorySet = new Set(visibleCategories);
                
                Object.keys(this.elementRegistry).forEach(category => {
                    const selectors = this.elementRegistry[category];
                    const show = categorySet.has(category);
                    
                    selectors.forEach(selector => {
                        const elements = document.querySelectorAll(selector);
                        elements.forEach(el => {
                            el.style.display = show ? '' : 'none';
                        });
                    });
                });
            },

            /**
             * 关闭所有已打开的 API 相关页面
             */
            _closeOpenPages: function() {
                this.elementRegistry.pages.forEach(selector => {
                    const page = document.querySelector(selector);
                    if (page) {
                        // 检查页面是否处于打开状态
                        if (page.classList.contains('active') || 
                            (page.style.display && page.style.display !== 'none')) {
                            page.classList.remove('active');
                            page.style.display = 'none';
                        }
                    }
                });

                // 关闭聊天模式选择面板
                const chatModeOverlay = document.getElementById('chatModeOverlay');
                if (chatModeOverlay) {
                    chatModeOverlay.classList.remove('show');
                    chatModeOverlay.style.display = 'none';
                }
            },

            /**
             * 设置事件监听器
             */
            _setupListeners: function() {
                // 监听 storage 事件，以便在其他标签页修改设置时同步
                window.addEventListener('storage', (e) => {
                    if (e.key === 'ai_service_config') {
                        this.refresh();
                    }
                });
            },

            /**
             * 动态注册新的元素选择器
             * @param {string} category - 类别名称
             * @param {string|string[]} selectors - 选择器或选择器数组
             */
            registerElements: function(category, selectors) {
                if (!this.elementRegistry[category]) {
                    this.elementRegistry[category] = [];
                }
                const selectorArray = Array.isArray(selectors) ? selectors : [selectors];
                this.elementRegistry[category].push(...selectorArray);
                
                // 立即应用当前状态到新注册的元素
                this._applyVisibility();
            },

            /**
             * 获取特定类别的所有元素
             * @param {string} category - 类别名称
             * @returns {Element[]}
             */
            getElementsByCategory: function(category) {
                const selectors = this.elementRegistry[category] || [];
                const elements = [];
                selectors.forEach(selector => {
                    const found = document.querySelectorAll(selector);
                    elements.push(...Array.from(found));
                });
                return elements;
            }
        };

