            clearChatHistoryInDb: async function(chatId) {
                const core = window.Core && window.Core.StorageService;
                if (!core || !chatId) return;

                const clearStoreByChatId = async (dbName, storeName) => {
                    let db;
                    try {
                        db = await core.openDB(dbName);
                    } catch (e) {
                        return;
                    }
                    if (!db || !db.objectStoreNames || !db.objectStoreNames.contains(storeName)) return;

                    await core.transaction(dbName, [storeName], async (tx) => {
                        const store = tx.objectStore(storeName);
                        const canUseIndex = store.indexNames && store.indexNames.contains && store.indexNames.contains('chatId') && typeof IDBKeyRange !== 'undefined';
                        await new Promise((resolve, reject) => {
                            const request = canUseIndex
                                ? store.index('chatId').openCursor(IDBKeyRange.only(chatId))
                                : store.openCursor();

                            request.onsuccess = (event) => {
                                const cursor = event.target.result;
                                if (!cursor) {
                                    resolve();
                                    return;
                                }
                                if (canUseIndex || (cursor.value && String(cursor.value.chatId) === String(chatId))) {
                                    cursor.delete();
                                }
                                cursor.continue();
                            };
                            request.onerror = () => reject(request.error);
                        });
                    });
                };

                await clearStoreByChatId('ChatStorageDB', 'messages');
                await clearStoreByChatId('PhoneAppImages', 'messages');
            },
            
