            clearChatMemory: function(targetChatId) {
                const chatId = targetChatId || appData.currentDialogue;
                const chat = appData.chats.find(c => c.id === chatId);
                if (!chat) {
                    showNotification('未找到当前聊天', 'error');
                    return false;
                }
                const messages = Array.isArray(chat.messages) ? chat.messages : [];
                const lastMessage = messages.length ? messages[messages.length - 1] : null;
                let cutoff = Date.now();
                if (lastMessage) {
                    const rawTime = lastMessage.time || lastMessage.timestamp || lastMessage.id;
                    const parsed = typeof rawTime === 'number' ? rawTime : Date.parse(rawTime);
                    if (!Number.isNaN(parsed) && parsed > 0) cutoff = parsed;
                }
                chat.prevMemoryCutoff = chat.memoryCutoff || null;
                chat.memoryCutoff = cutoff;
                if (!Array.isArray(chat.messages)) {
                    chat.messages = messages;
                }
                const restartTime = new Date().toISOString();
                const restartMessage = {
                    id: `${Date.now()}-restart`,
                    type: 'system',
                    text: '聊天已重启，开始新的对话',
                    time: restartTime,
                    isComment: true,
                    isFixedSystemPrompt: true
                };
                chat.messages.push(restartMessage);
                chat.lastMessage = restartMessage.text;
                chat.lastMessageTime = restartTime;
                saveData();
                initChatList();
                if (appData.currentDialogue === chatId) {
                    loadDialogueMessages(chatId);
                }
                showNotification('已重启聊天', 'success');
                return true;
            },

